mapper.select:
select DMZD, DMZDZWM, DM, DMMC from  dd_bddm t
where t.dmzd = #{dmzd}

    and  t.dmmc like '%${dmmc}%'

select distinct t.dmmc from  dd_bddm t
where t.dmzd = #{dmzd}

    and  t.dmmc like '%${dmmc}%'

mapper.insert:
insert into dd_bddm(DMZD,DMZDZWM,DM,DMMC) select * from(
select #{record.dmzd,jdbcType=VARCHAR}, #{record.dmzdzwm,jdbcType=VARCHAR}, #{record.dm,jdbcType=VARCHAR}, #{record.dmmc,jdbcType=VARCHAR} from dual
)

mapper.delete:
delete from  dd_bddm d
where d.dmzd = #{dmzd}
  and d.dmzdzwm = #{dmzdzwm}
  and d.dm = #{dm}
  and d.dmmc = #{dmmc}
